import csv
import os
from datetime import datetime

import modal

app = modal.App("etl-pipeline-orchestrator")

volume = modal.Volume.from_name("etl-pipeline-orchestrator-vol", create_if_missing=True)
secret = modal.Secret.from_name("etl-pipeline-orchestrator-secret")
output_dict = modal.Dict.from_name("etl-pipeline-orchestrator-output", create_if_missing=True)

DATA_PATH = "/data/output.csv"


@app.cls(
    volumes={"/data": volume},
    secrets=[secret],
    timeout=300,
)
class EtlPipeline:
    @modal.enter()
    def setup(self):
        self.db_url = os.environ.get("DB_URL", "")
        self.api_token = os.environ.get("API_TOKEN", "")

    def extract(self):
        records = [
            {"id": 1, "value": "alpha"},
            {"id": 2, "value": "beta"},
            {"id": 3, "value": "gamma"},
        ]
        return records

    def transform(self, records):
        transformed = []
        for record in records:
            transformed.append(
                {
                    "id": record["id"],
                    "value": record["value"].upper(),
                    "processed_at": datetime.utcnow().isoformat(),
                }
            )
        return transformed

    def load(self, records):
        os.makedirs(os.path.dirname(DATA_PATH), exist_ok=True)
        with open(DATA_PATH, "w", newline="", encoding="utf-8") as handle:
            writer = csv.DictWriter(handle, fieldnames=["id", "value", "processed_at"])
            writer.writeheader()
            writer.writerows(records)

    def run_pipeline(self):
        records = self.extract()
        transformed = self.transform(records)
        self.load(transformed)
        volume.commit()
        return {
            "records_extracted": len(records),
            "records_loaded": len(transformed),
            "pipeline_status": "success",
            "output_path": DATA_PATH,
        }


@app.function(schedule=modal.Period(hours=1))
def scheduled_etl():
    result = EtlPipeline().run_pipeline()
    return result


@app.local_entrypoint()
def main():
    result = EtlPipeline().run_pipeline()
    output_dict["records_extracted"] = result["records_extracted"]
    output_dict["records_loaded"] = result["records_loaded"]
    output_dict["pipeline_status"] = result["pipeline_status"]
    output_dict["output_path"] = result["output_path"]
    print("ETL pipeline complete:", result)

